### 1. System Status Endpoint (for Mission Control)
Add `GET /api/system/status` that returns REAL system data:

```javascript
app.get('/api/system/status', async () => {
  const os = await import('os')

  // CPU usage
  const cpus = os.cpus()
  const loadAvg = os.loadavg()

  // Memory
  const totalMem = os.totalmem()
  const freeMem = os.freemem()
  const usedMem = totalMem - freeMem

  // Disk (df command)
  let disk = { total: 0, used: 0, available: 0, percent: '0%' }
  try {
    const output = execSync("df -BG / | tail -1 | awk '{print $2,$3,$4,$5}'").toString().trim().split(/\s+/)
    disk = { total: output[0], used: output[1], available: output[2], percent: output[3] }
  } catch {}

  // PM2 processes
  let pm2 = []
  try {
    const pm2Out = execSync('pm2 jlist 2>/dev/null').toString()
    pm2 = JSON.parse(pm2Out).map(p => ({
      name: p.name, status: p.pm2_env?.status || 'unknown',
      memory: p.monit?.memory || 0, cpu: p.monit?.cpu || 0,
      uptime: p.pm2_env?.pm_uptime || 0, restarts: p.pm2_env?.restart_time || 0,
      pid: p.pid
    }))
  } catch {}

  // OpenClaw gateway probe
  let gateway = { status: 'unknown' }
  try {
    const ctrl = new AbortController()
    const timer = setTimeout(() => ctrl.abort(), 3000)
    const resp = await fetch('http://127.0.0.1:18789/', { signal: ctrl.signal })
    clearTimeout(timer)
    gateway = { status: 'connected', code: resp.status }
  } catch (e) {
    gateway = { status: 'disconnected', error: e.message }
  }

  return {
    cpu: { loadAvg, cores: cpus.length },
    memory: { total: totalMem, used: usedMem, free: freeMem, percent: (usedMem/totalMem*100).toFixed(1) },
    disk, pm2, gateway,
    uptime: os.uptime(),
    hostname: os.hostname()
  }
})
```

### 2. Pipeline CRM Endpoints (real deal management)
Create data file: `~/magi-v2/backend/data/pipeline.json` with initial content: `{"deals":[],"nextId":1}`

Add these endpoints:
```javascript
const PIPELINE_DATA = join(__dirname, 'data', 'pipeline.json')
function loadPipeline() { try { return JSON.parse(readFileSync(PIPELINE_DATA,'utf8')) } catch { return {deals:[],nextId:1} } }
function savePipeline(d) { writeFileSync(PIPELINE_DATA, JSON.stringify(d,null,2)) }

// GET /api/pipeline
app.get('/api/pipeline', async () => {
  const data = loadPipeline()
  const stages = ['lead','contacted','meeting','proposal','negotiation','won','lost']
  const stats = {}
  for (const s of stages) stats[s] = { count:0, value:0 }
  for (const d of data.deals) { if(stats[d.stage]) { stats[d.stage].count++; stats[d.stage].value += d.value||0 } }
  const won = stats.won?.count||0, lost = stats.lost?.count||0
  const winRate = (won+lost)>0 ? (won/(won+lost)*100).toFixed(1) : 0
  return { ok:true, deals: data.deals, stages, stats, winRate }
})

// POST /api/pipeline (create deal)
app.post('/api/pipeline', async (req) => {
  const data = loadPipeline()
  const { name, business, value, stage, notes, phone } = req.body || {}
  if (!name) return { ok:false, error:'Name required' }
  const deal = { id:data.nextId++, name, business:business||'', value:parseInt(value)||0,
    stage:stage||'lead', notes:notes||'', phone:phone||'',
    createdAt:Date.now(), updatedAt:Date.now(),
    activities:[{type:'created',ts:Date.now(),note:'Deal created'}] }
  data.deals.push(deal)
  savePipeline(data)
  // Also create notification
  addNotification('pipeline', `New deal: ${name}`, `Value: Rp ${(deal.value||0).toLocaleString()}`)
  return { ok:true, deal }
})

// PUT /api/pipeline/:id (update deal)
app.put('/api/pipeline/:id', async (req) => {
  const data = loadPipeline()
  const deal = data.deals.find(d => d.id === parseInt(req.params.id))
  if (!deal) return { ok:false, error:'Not found' }
  const oldStage = deal.stage
  const updates = req.body || {}
  for (const [k,v] of Object.entries(updates)) {
    if (['name','business','value','stage','notes','phone'].includes(k)) deal[k] = v
  }
  deal.updatedAt = Date.now()
  if (updates.stage && updates.stage !== oldStage) {
    deal.activities = deal.activities || []
    deal.activities.push({type:'stage_change',from:oldStage,to:updates.stage,ts:Date.now()})
    addNotification('pipeline', `Deal moved: ${deal.name}`, `${oldStage} → ${updates.stage}`)
  }
  savePipeline(data)
  return { ok:true, deal }
})

// DELETE /api/pipeline/:id
app.delete('/api/pipeline/:id', async (req) => {
  const data = loadPipeline()
  data.deals = data.deals.filter(d => d.id !== parseInt(req.params.id))
  savePipeline(data)
  return { ok:true }
})
```

### 3. Notification System (REAL event triggers)
Create data file: `~/magi-v2/backend/data/notifications.json` with initial: `{"items":[],"nextId":1}`

```javascript
const NOTIF_FILE = join(__dirname, 'data', 'notifications.json')
function loadNotifs() { try { return JSON.parse(readFileSync(NOTIF_FILE,'utf8')) } catch { return {items:[],nextId:1} } }
function saveNotifs(d) { writeFileSync(NOTIF_FILE, JSON.stringify(d,null,2)) }

function addNotification(category, title, body) {
  const data = loadNotifs()
  data.items.unshift({ id:data.nextId++, category, title, body, read:false, createdAt:Date.now() })
  if (data.items.length > 200) data.items = data.items.slice(0, 200) // cap at 200
  saveNotifs(data)
}

// Replace the existing GET /api/notifications
// Find the current one and replace it with:
app.get('/api/notifications', async (req) => {
  const data = loadNotifs()
  const unread = data.items.filter(n => !n.read).length
  return { ok:true, items: data.items.slice(0, 50), total: data.items.length, unread }
})

app.put('/api/notifications/read', async (req) => {
  const { id, all } = req.body || {}
  const data = loadNotifs()
  if (all) { data.items.forEach(n => n.read = true) }
  else if (id) { const n = data.items.find(i => i.id === id); if(n) n.read = true }
  saveNotifs(data)
  return { ok:true }
})

app.delete('/api/notifications', async () => {
  saveNotifs({items:[],nextId:loadNotifs().nextId})
  return { ok:true }
})
```

