### 4. Reports Generation
Create data file: `~/magi-v2/backend/data/reports.json` with initial: `{"reports":[],"nextId":1}`

```javascript
const REPORTS_FILE = join(__dirname, 'data', 'reports.json')
function loadReports() { try { return JSON.parse(readFileSync(REPORTS_FILE,'utf8')) } catch { return {reports:[],nextId:1} } }
function saveReports(d) { writeFileSync(REPORTS_FILE, JSON.stringify(d,null,2)) }

app.get('/api/reports', async () => {
  return { ok:true, reports: loadReports().reports }
})

app.post('/api/reports/generate', async (req) => {
  // Pull real data from other sources
  const analytics = loadAnalytics() // use existing loadAnalytics function
  const tasks = loadTasks() // use existing task loader
  const pipeline = loadPipeline()
  const sessions = listSessions()

  const now = new Date()
  const weekAgo = Date.now() - 7*24*60*60*1000

  // Calculate real metrics
  const recentSessions = sessions.filter(s => s.createdAt > weekAgo)
  const totalTokens = (analytics.totalTokens || 0)
  const totalCost = (analytics.totalCost || 0)
  const tasksDone = (tasks.tasks||[]).filter(t => t.status === 'done').length
  const tasksTotal = (tasks.tasks||[]).length
  const dealCount = pipeline.deals?.length || 0
  const dealValue = pipeline.deals?.reduce((s,d) => s + (d.value||0), 0) || 0

  const report = {
    id: loadReports().nextId,
    title: `Weekly Report — ${now.toISOString().slice(0,10)}`,
    generatedAt: Date.now(),
    period: { from: weekAgo, to: Date.now() },
    data: {
      sessions: recentSessions.length,
      totalTokens,
      totalCost: totalCost.toFixed(2),
      tasksCompleted: tasksDone,
      tasksTotal,
      pipelineDeals: dealCount,
      pipelineValue: dealValue,
      topAgents: analytics.perAgent || {}
    }
  }

  const data = loadReports()
  data.reports.unshift(report)
  data.nextId++
  if (data.reports.length > 52) data.reports = data.reports.slice(0, 52) // keep 1 year
  saveReports(data)
  addNotification('reports', 'New report generated', report.title)
  return { ok:true, report }
})
```

### 5. Broadcast (WA Message Sending via OpenClaw)
Find the existing `POST /api/whatsapp/send` endpoint. It should already connect to the OpenClaw gateway for message sending. Check if it works. If it uses the MAGI internal agent chat instead, modify it to use OpenClaw's gateway proxy.

Read the existing implementation first. The key is: broadcast needs to send WhatsApp messages through the same mechanism OpenClaw uses. Check if there's a gateway proxy URL or if MAGI calls Bedrock directly.

Add broadcast endpoints:
```javascript
const BROADCAST_FILE = join(__dirname, 'data', 'broadcasts.json')
function loadBroadcasts() { try { return JSON.parse(readFileSync(BROADCAST_FILE,'utf8')) } catch { return {logs:[],nextId:1} } }
function saveBroadcasts(d) { writeFileSync(BROADCAST_FILE, JSON.stringify(d,null,2)) }

app.get('/api/broadcast/logs', async () => {
  return { ok:true, logs: loadBroadcasts().logs.slice(0, 50) }
})

app.post('/api/broadcast/send', async (req) => {
  if (!requireAdmin(req)) return { ok:false, error:'Admin required' }
  const { recipients, template, variables } = req.body || {}
  if (!recipients?.length || !template) return { ok:false, error:'Recipients and template required' }

  const results = []
  const data = loadBroadcasts()

  for (const recipient of recipients) {
    // Apply template variables
    let msg = template
    if (variables) {
      for (const [k,v] of Object.entries(variables)) {
        msg = msg.replace(new RegExp(`\\{\\{${k}\\}\\}`, 'g'), v)
      }
    }
    msg = msg.replace(/\{\{name\}\}/g, recipient.name || '')
    msg = msg.replace(/\{\{phone\}\}/g, recipient.phone || '')

    try {
      // Use OpenClaw gateway proxy to send WA message
      // The existing /api/whatsapp/send endpoint handles this
      // We call it internally
      const sendResult = await sendWhatsApp(recipient.phone, msg)
      results.push({ phone: recipient.phone, name: recipient.name, status: 'sent', ts: Date.now() })

      // Rate limit: 1 message per second
      await new Promise(r => setTimeout(r, 1000))
    } catch (e) {
      results.push({ phone: recipient.phone, name: recipient.name, status: 'failed', error: e.message, ts: Date.now() })
    }
  }

  const log = { id: data.nextId++, template, recipientCount: recipients.length, 
    sentCount: results.filter(r=>r.status==='sent').length, results, createdAt: Date.now() }
  data.logs.unshift(log)
  data.nextId++
  saveBroadcasts(data)
  addNotification('broadcast', `Broadcast sent: ${log.sentCount}/${recipients.length}`, template.slice(0,50))
  return { ok:true, log }
})
```

For `sendWhatsApp`, check if there's already a function in server.js that sends WA messages. If so, reuse it. If not, create one that POSTs to the OpenClaw gateway:
```javascript
async function sendWhatsApp(phone, message) {
  // Try OpenClaw gateway proxy
  const gwToken = process.env.OPENCLAW_GATEWAY_TOKEN || ''
  const resp = await fetch('http://127.0.0.1:18789/api/message', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + gwToken },
    body: JSON.stringify({ action: 'send', target: phone, message })
  })
  if (!resp.ok) throw new Error('Gateway send failed: ' + resp.status)
  return await resp.json()
}
```
NOTE: Check the actual OpenClaw gateway API for message sending — it may use a different endpoint. Read the OpenClaw docs or check the gateway health endpoint.

### 6. ICat Contacts — Make Import Work
The ICat endpoints already exist and work (contacts, templates, rules CRUD). The problem is 0 contacts. Add an import-from-leads endpoint:
```javascript
app.post('/api/icat/contacts/import-from-leads', async (req) => {
  const { indices } = req.body || {}
  if (!indices?.length) return { ok:false, error:'No leads selected' }
  const leads = loadLeads()
  const contacts = loadContacts()
  let imported = 0
  for (const idx of indices) {
    const lead = leads[idx]
    if (!lead) continue
    const phone = lead.telepon || lead.wa_number || ''
    if (!phone) continue
    // Check if already exists
    if (contacts.items.some(c => c.phone === phone)) continue
    contacts.items.push({
      id: contacts.nextId++, name: lead.nama||'Unknown', phone,
      business: lead.jenis||lead.kategori||'', city: lead.kota||'',
      province: lead.provinsi||'', tags: [], notes: '',
      createdAt: Date.now(), lastContact: null
    })
    imported++
  }
  saveContacts(contacts)
  addNotification('icat', `${imported} contacts imported from leads`, '')
  return { ok:true, imported }
})
```

