const PROVIDER_FILE = join(__dirname, 'data', 'provider.json')
function loadProvider() { try { if (existsSync(PROVIDER_FILE)) return JSON.parse(readFileSync(PROVIDER_FILE, 'utf8')) } catch {} return { default: 'bedrock', ollama: { url: 'http://localhost:11434', model: 'qwen2.5:32b' }, perAgent: {} } }
function saveProvider(d) { writeFileSync(PROVIDER_FILE, JSON.stringify(d, null, 2)) }

function getProviderForAgent(agentId) {
  const prov = loadProvider()
  return prov.perAgent?.[agentId] || prov.default || 'bedrock'
}

async function* streamOllama(systemPrompt, userText, signal, agentId) {
  const prov = loadProvider()
  const ollamaUrl = prov.ollama?.url || 'http://localhost:11434'
  const ollamaModel = prov.ollama?.model || 'qwen2.5:32b'
  console.log(`[Ollama] agent=${agentId} model=${ollamaModel}`)

  const resp = await fetch(`${ollamaUrl}/api/chat`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({

[2195 more lines in file. Use offset=201 to continue.]

      model: ollamaModel,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userText }
      ],
      stream: true
    }),
    signal
  })

  if (!resp.ok) throw new Error(`Ollama error: ${resp.status}`)
  let inputTokens = 0, outputTokens = 0
  const reader = resp.body.getReader()
  const decoder = new TextDecoder()
  let buffer = ''

  while (true) {
    const { done, value } = await reader.read()
    if (done) break
    if (signal?.aborted) break
    buffer += decoder.decode(value, { stream: true })
    const lines = buffer.split('\n')
    buffer = lines.pop() || ''
    for (const line of lines) {
      if (!line.trim()) continue
      try {
        const json = JSON.parse(line)
        if (json.message?.content) yield json.message.content
        if (json.eval_count) outputTokens = json.eval_count
        if (json.prompt_eval_count) inputTokens = json.prompt_eval_count
      } catch {}
    }
  }
  try { trackUsage(agentId || 'unknown', ollamaModel, inputTokens, outputTokens) } catch {}
}

// ── Unified Stream (Bedrock or Ollama) ──────────────────
async function* streamAI(systemPrompt, userText, signal, agentId) {
  const provider = getProviderForAgent(agentId)
  if (provider === 'ollama') {
    yield* streamOllama(systemPrompt, userText, signal, agentId)
  } else {
    yield* streamBedrock(systemPrompt, userText, signal, agentId)
  }
}

// ── Agent Tools: Web Search ─────────────────────────────
const TAVILY_KEY = process.env.TAVILY_API_KEY || (() => { try { return readFileSync(join(HOME, '.tavily_key'), 'utf8').trim() } catch { return '' } })()

async function webSearch(query, maxResults = 5) {
  if (!TAVILY_KEY) {
    // Fallback to ~/bin/search if available
    try {
      const result = execSync(`${HOME}/bin/search "${query.replace(/"/g, '\\"')}" 2>/dev/null`, { encoding: 'utf8', timeout: 15000 })
      return result.slice(0, 2000)
    } catch { return 'Search unavailable — no Tavily key or search CLI found.' }
  }
  try {
    const resp = await fetch('https://api.tavily.com/search', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ api_key: TAVILY_KEY, query, max_results: maxResults, include_answer: true })
    })
    const data = await resp.json()
    let text = data.answer ? `Answer: ${data.answer}\n\n` : ''
    for (const r of (data.results || []).slice(0, maxResults)) {
      text += `• ${r.title}\n  ${r.url}\n  ${r.content?.slice(0, 200) || ''}\n\n`
    }
    return text || 'No results found.'
  } catch (e) { return `Search error: ${e.message}` }
}

// ── Agent Tools: File Read ──────────────────────────────
function readLocalFile(filePath) {
  try {
    const safe = resolve(HOME, filePath)
    if (!safe.startsWith(HOME)) return 'Access denied — path outside home directory.'
    if (!existsSync(safe)) return `File not found: ${filePath}`
    const stat = statSync(safe)
    if (stat.isDirectory()) {
      const items = readdirSync(safe).slice(0, 50)
      return `Directory listing (${items.length} items):\n` + items.join('\n')
    }
    if (stat.size > 100000) return `File too large (${stat.size} bytes). Max 100KB.`
    return readFileSync(safe, 'utf8')
  } catch (e) { return `Error reading file: ${e.message}` }
}

