app.post('/api/auth/register', async (req) => {
  const { username, password } = req.body || {}
  if (!username || !password) return { ok: false, error: 'Username and password required' }
  if (username.length < 3 || username.length > 20) return { ok: false, error: 'Username must be 3-20 characters' }
  if (!/^[a-zA-Z0-9_]+$/.test(username)) return { ok: false, error: 'Username: letters, numbers, underscore only' }
  if (password.length < 6) return { ok: false, error: 'Password must be at least 6 characters' }
  const auth = loadAuth()
  if (auth.users[username]) return { ok: false, error: 'Username already taken' }
  if (!auth.pending) auth.pending = {}
  if (auth.pending[username]) return { ok: false, error: 'Registration already pending approval' }
  auth.pending[username] = { password, requestedAt: Date.now(), status: 'pending' }
  saveAuth(auth)
  trackEvent('auth_register_request', { username })
  return { ok: true, message: 'Registration submitted — awaiting admin approval' }
})

