      fromLabel: meta[r.from]?.label || r.from,
      toLabel: meta[r.to]?.label || r.to
    }))
    return { ok: true, rules: enriched }
  } catch (e) {
    return { ok: false, error: e.message }
  }
})

// PUT — update a rule by index
app.put('/wa-forward-rules', async (req) => {
  try {
    const { index, from, action, to, label } = req.body || {}
    if (index === undefined || index === null) return { ok: false, error: 'index required' }
    const rules = loadForwardRules()
    if (index < 0 || index >= rules.length) return { ok: false, error: 'Invalid index' }
    if (action && !['forward', 'forward_summarize', 'notify'].includes(action)) return { ok: false, error: 'Invalid action' }
    if (from !== undefined) rules[index].from = formatNumber(from)
    if (action !== undefined) rules[index].action = action
    if (to !== undefined) rules[index].to = formatNumber(to)
    if (label !== undefined) rules[index].label = label
    saveForwardRules(rules)
    trackEvent('wa_forward_rule_update', { index, ...rules[index] })
    const meta = readWAContacts()
    const enriched = rules.map((r, i) => ({
      ...r, index: i,
      fromLabel: meta[r.from]?.label || r.from,
      toLabel: meta[r.to]?.label || r.to
    }))
    return { ok: true, rules: enriched }
  } catch (e) {
    return { ok: false, error: e.message }
  }
})

