  } catch (e) { content = '(Content file not found)' }
  return { ok: true, entry: { ...entry, content } }
})

// POST /api/knowledge-base — save new entry
app.post('/api/knowledge-base', async (req) => {
  const { title, category, tags, content, summary, source } = req.body || {}
  if (!title || !content) return { ok: false, error: 'title and content required' }
  const data = loadKBIndex()
  const id = crypto.randomUUID()
  const slug = slugify(title)
  let filename = slug + '.md'
  if (existsSync(join(KB_DIR, filename))) {
    let c = 2
    while (existsSync(join(KB_DIR, slug + '-' + c + '.md'))) c++
    filename = slug + '-' + c + '.md'
  }
  const now = new Date().toISOString()
  const words = content.split(/\s+/).filter(Boolean).length
  const entry = {
    id,
    title,
    category: category || 'research',
    tags: Array.isArray(tags) ? tags : (tags || 'general').split(',').map(t => t.trim()).filter(Boolean),
    summary: summary || content.replace(/#/g, '').replace(/\n/g, ' ').trim().substring(0, 200),
    content_file: filename,
    created: now,
    updated: now,
    source: source || 'magi-web',
    word_count: words
  }
  writeFileSync(join(KB_DIR, filename), content)
  data.entries.push(entry)
  saveKBIndex(data)
  return { ok: true, entry }
})

// PUT /api/knowledge-base/:id — update entry
app.put('/api/knowledge-base/:id', async (req) => {
  const data = loadKBIndex()
  const idx = (data.entries || []).findIndex(e => e.id === req.params.id)
  if (idx < 0) return { ok: false, error: 'Entry not found' }
  const { title, category, tags, content, summary } = req.body || {}
  const entry = data.entries[idx]
  if (title) entry.title = title
  if (category) entry.category = category
  if (tags) entry.tags = Array.isArray(tags) ? tags : tags.split(',').map(t => t.trim()).filter(Boolean)
  if (summary) entry.summary = summary
  entry.updated = new Date().toISOString()
  if (content) {
    writeFileSync(join(KB_DIR, entry.content_file), content)
    entry.word_count = content.split(/\s+/).filter(Boolean).length
  }
  data.entries[idx] = entry
  saveKBIndex(data)
  return { ok: true, entry }
})

// DELETE /api/knowledge-base/:id — delete entry
app.delete('/api/knowledge-base/:id', async (req) => {
  const data = loadKBIndex()
  const idx = (data.entries || []).findIndex(e => e.id === req.params.id)
  if (idx < 0) return { ok: false, error: 'Entry not found' }
  const entry = data.entries[idx]
  try {
    const fp = join(KB_DIR, entry.content_file)
    if (existsSync(fp)) unlinkSync(fp)
  } catch {}
  data.entries.splice(idx, 1)
  saveKBIndex(data)
  return { ok: true }
})

