app.post('/api/reports/generate', async (req) => {
  const analytics = loadAnalytics()
  const tasks = loadTasks()
  const pipeline = loadPipeline()
  const sessions = listSessions()

  const now = new Date()
  const weekAgo = Date.now() - 7 * 24 * 60 * 60 * 1000

  const recentSessions = sessions.filter(s => s.createdAt > weekAgo)
  const totalTokens = (analytics.totalTokens || 0)
  const totalCost = (analytics.totalCost || 0)
  const tasksDone = (tasks.tasks || []).filter(t => t.status === 'done').length
  const tasksTotal = (tasks.tasks || []).length
  const dealCount = pipeline.deals?.length || 0
  const dealValue = pipeline.deals?.reduce((s, d) => s + (d.value || 0), 0) || 0

  const data = loadReports()
  const report = {
    id: data.nextId,
    title: 'Weekly Report — ' + now.toISOString().slice(0, 10),
    generatedAt: Date.now(),
    period: { from: weekAgo, to: Date.now() },
    data: {
      sessions: recentSessions.length,
      totalTokens,
      totalCost: totalCost.toFixed(2),
      tasksCompleted: tasksDone,
      tasksTotal,
      pipelineDeals: dealCount,
      pipelineValue: dealValue,
      topAgents: analytics.perAgent || {}
    }
  }

  data.reports.unshift(report)
  data.nextId++
  if (data.reports.length > 52) data.reports = data.reports.slice(0, 52)
  saveReports(data)
  addNotification('New report generated', report.title, 'info', 'reports')
  trackEvent('report_generated', { id: report.id, title: report.title })
  return { ok: true, report }
})

