function saveBroadcasts(d) { writeFileSync(BROADCAST_FILE, JSON.stringify(d, null, 2)) }

async function sendWhatsApp(phone, message) {
  const gwToken = process.env.OPENCLAW_GATEWAY_TOKEN || ''
  const resp = await fetch('http://127.0.0.1:18789/api/message', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + gwToken },
    body: JSON.stringify({ action: 'send', target: phone, message })
  })
  if (!resp.ok) throw new Error('Gateway send failed: ' + resp.status)
  return await resp.json()
}

app.get('/api/broadcast/logs', async () => {
  return { ok: true, logs: loadBroadcasts().logs.slice(0, 50) }
})

app.post('/api/broadcast/send', async (req) => {
  if (!requireAdmin(req)) return { ok: false, error: 'Admin required' }
  const { recipients, template, variables } = req.body || {}
  if (!recipients?.length || !template) return { ok: false, error: 'Recipients and template required' }

  const results = []

  for (const recipient of recipients) {
    let msg = template
    if (variables) {
      for (const [k, v] of Object.entries(variables)) {
        msg = msg.replace(new RegExp('\\{\\{' + k + '\\}\\}', 'g'), v)
      }
    }
    msg = msg.replace(/\{\{name\}\}/g, recipient.name || '')
    msg = msg.replace(/\{\{phone\}\}/g, recipient.phone || '')

    try {
      await sendWhatsApp(recipient.phone, msg)
      results.push({ phone: recipient.phone, name: recipient.name, status: 'sent', ts: Date.now() })
      await new Promise(r => setTimeout(r, 1000))
    } catch (e) {
      results.push({ phone: recipient.phone, name: recipient.name, status: 'failed', error: e.message, ts: Date.now() })
    }
  }

  const data = loadBroadcasts()
  const log = {
    id: data.nextId++, template, recipientCount: recipients.length,
    sentCount: results.filter(r => r.status === 'sent').length,
    results, createdAt: Date.now()
  }
  data.logs.unshift(log)
  if (data.logs.length > 200) data.logs = data.logs.slice(0, 200)
  saveBroadcasts(data)
  addNotification('Broadcast sent: ' + log.sentCount + '/' + recipients.length, template.slice(0, 50), 'info', 'broadcast')
  trackEvent('broadcast_send', { sentCount: log.sentCount, recipientCount: recipients.length })
  return { ok: true, log }
})

