// Import from leads by indices
app.post('/api/icat/contacts/import-from-leads', async (req) => {
  const { indices } = req.body || {}
  if (!indices?.length) return { ok: false, error: 'No leads selected' }
  const leads = loadLeads()
  const data = loadContacts()
  const existing = new Set(data.contacts.map(c => c.phone || c.waNumber))
  let imported = 0
  for (const idx of indices) {
    const lead = leads[idx]
    if (!lead) continue
    const phone = lead.telepon || lead.wa_number || ''
    if (!phone) continue
    if (existing.has(phone)) continue
    data.contacts.push({
      id: data.nextId++, name: lead.nama || 'Unknown', phone,
      waNumber: lead.wa_number || phone,
      business: lead.jenis || lead.kategori || '',
      province: lead.provinsi || '', city: lead.kota || '',
      tags: [], notes: '', score: lead.score || 50,
      status: 'new', optedOut: false,
      createdAt: Date.now(), updatedAt: Date.now(),
      lastContact: null, messageCount: 0
    })
    existing.add(phone)
    imported++
  }
  saveContacts(data)
  addNotification(imported + ' contacts imported from leads', '', 'info', 'icat')
  trackEvent('icat_import_from_leads', { count: imported, indices: indices.length })
  return { ok: true, imported }
})

